import React, { useState } from "react";

export default function SavingsDepositScreen({ savingsBalance, onDeposit, showNotification }) {
  const [amount, setAmount] = useState("");

  const handleDeposit = () => {
    const value = parseFloat(amount);
    if (!value || value <= 0) {
      showNotification("Enter a valid amount", "error");
      return;
    }
    if (value > savingsBalance) {
      showNotification("Insufficient main balance for savings deposit", "error");
      return;
    }
    onDeposit(value);
    showNotification(`Deposited $${value} to savings successfully!`, "success");
    setAmount("");
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Deposit into Savings</h1>
      <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm space-y-4">
        <p className="text-gray-500">Current savings: ${savingsBalance}</p>
        <input
          type="number"
          placeholder="Enter amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className="w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-teal-500"
        />
        <button
          onClick={handleDeposit}
          className="w-full py-3 bg-teal-600 text-white rounded-xl hover:bg-teal-700 transition-colors"
        >
          Deposit to Savings
        </button>
      </div>
    </div>
  );
}
